(window.webpackJsonp=window.webpackJsonp||[]).push([[129],{950:function(n,o,e){"use strict";e.r(o);var t=e(1),r=function(n){n.options.__data__block__={presentation_1a96284a:"\n---\n\n二叉搜索树（Binary Search Tree，后文简写 BST）的特性\n\n- 对于 BST 的每一个节点node，左子树节点的值都比node的值要小，右子树节点的值都比node的值大。\n- 对于 BST 的每一个节点node，它的左侧子树和右侧子树都是 BST。\n\n<font color=red>从做算法题的角度来看 BST，除了它的定义，还有一个重要的性质：BST 的中序遍历结果是有序的（升序）。</font>\n\n---\n\n## 230-二叉搜索树中第K小的元素\n\n给定一个二叉搜索树的根节点 root ，和一个整数 k ，请你设计一个算法查找其中第 k 个最小元素（从 1 开始计数）。\n\n--\n\n![](./img/230/1.png)\n\n--\n\n![](./img/230/2.png)\n\n--\n\n```java\nclass Solution {\n    List<Integer> valList = new ArrayList();\n    public int kthSmallest(TreeNode root, int k) {\n        traverse(root);\n        return valList.get(k-1);\n    }\n\n    void traverse(TreeNode root){\n        if (null == root){\n            return;\n        }\n        traverse(root.left);\n        valList.add(root.val);\n        traverse(root.right);\n    }\n}\n```\n\n---\n\n## 538-把二叉搜索树转换为累加树(1038)\n\n给出二叉搜索树的根节点，该树的节点值各不相同，请你将其转换为累加树（Greater Sum Tree），使每个节点node的新值等于原树中大于或等于node.val的值之和。\n\n提醒一下，二叉搜索树满足下列约束条件：\n\n- 节点的左子树仅包含键 小于 节点键的节点。\n- 节点的右子树仅包含键 大于 节点键的节点。\n- 左右子树也必须是二叉搜索树。\n\n--\n\n![](./img/538/1.png)\n\n--\n\n![](./img/538/2.png)\n\n--\n\n```java\nclass Solution {\n    public TreeNode convertBST(TreeNode root) {\n        traverse(root);\n        return root;\n    }\n    int sum =0;\n    void traverse(TreeNode root){\n        if (null == root){\n            return;\n        }\n        traverse(root.right);\n        sum+=root.val;\n        root.val = sum;\n        traverse(root.left);\n    }\n}\n```\n\n---\n\n## 判断 BST 的合法性\n\n1. 中序遍历，破坏了升序的即false\n2. 递归， 以 root 为根的子树节点必须满足 max.val > root.val > min.val */\n\n--\n\n```java\nboolean isValidBST(TreeNode root) {\n    return isValidBST(root, null, null);\n}\n\n/* 限定以 root 为根的子树节点必须满足 max.val > root.val > min.val */\nboolean isValidBST(TreeNode root, TreeNode min, TreeNode max) {\n    // base case\n    if (root == null) return true;\n    // 若 root.val 不符合 max 和 min 的限制，说明不是合法 BST\n    if (min != null && root.val <= min.val) return false;\n    if (max != null && root.val >= max.val) return false;\n    // 限定左子树的最大值是 root.val，右子树的最小值是 root.val\n    return isValidBST(root.left, min, root) \n        && isValidBST(root.right, root, max);\n}\n```\n\n---\n\n## 在 BST 中搜索一个数\n\n```java\nvoid BST(TreeNode root, int target) {\n    if (root.val == target)\n        // 找到目标，做点什么\n    if (root.val < target) \n        BST(root.right, target);\n    if (root.val > target)\n        BST(root.left, target);\n}\n```\n\n---\n\n## 在 BST 中插入一个数\n\n```java\nTreeNode insertIntoBST(TreeNode root, int val) {\n    // 找到空位置插入新节点\n    if (root == null) return new TreeNode(val);\n    // if (root.val == val)\n    //     BST 中一般不会插入已存在元素\n    if (root.val < val) \n        root.right = insertIntoBST(root.right, val);\n    if (root.val > val) \n        root.left = insertIntoBST(root.left, val);\n    return root;\n}\n```\n\n---\n\n## 在 BST 中删除一个数\n\n找到目标节点了，比方说是节点 A，如何删除这个节点，这是难点。因为删除节点的同时不能破坏 BST 的性质。有三种情况\n- A 恰好是末端节点，两个子节点都为空，那么它可以当场去世了。\n- A 只有一个非空子节点，那么它要让这个孩子接替自己的位置。\n- A 有两个子节点，麻烦了，为了不破坏 BST 的性质，A 必须找到左子树中最大的那个节点，或者右子树中最小的那个节点来接替自己。我们以第二种方式讲解。\n```java\nTreeNode deleteNode(TreeNode root, int key) {\n    if (root == null) return null;\n    if (root.val == key) {\n        // 这两个 if 把情况 1 和 2 都正确处理了\n        if (root.left == null) return root.right;\n        if (root.right == null) return root.left;\n        // 处理情况 3\n        TreeNode minNode = getMin(root.right);\n        root.val = minNode.val;\n        root.right = deleteNode(root.right, minNode.val);\n    } else if (root.val > key) {\n        root.left = deleteNode(root.left, key);\n    } else if (root.val < key) {\n        root.right = deleteNode(root.right, key);\n    }\n    return root;\n}\n\nTreeNode getMin(TreeNode node) {\n    // BST 最左边的就是最小的\n    while (node.left != null) node = node.left;\n    return node;\n}\n```\n\n---\n\n## 450-删除二叉搜索树中的节点\n\n给定一个二叉搜索树的根节点 root 和一个值 key，删除二叉搜索树中的 key 对应的节点，并保证二叉搜索树的性质不变。返回二叉搜索树（有可能被更新）的根节点的引用。\n\n说明： 要求算法时间复杂度为 O(h)，h 为树的高度。\n\n--\n\n![](./img/538/1.png)\n\n---\n\n## 701-二叉搜索树中的插入操作\n\n给定二叉搜索树（BST）的根节点和要插入树中的值，将值插入二叉搜索树。 返回插入后二叉搜索树的根节点。 输入数据 保证 ，新值和原始二叉搜索树中的任意节点值都不同。\n\n注意，可能存在多种有效的插入方式，只要树在插入后仍保持为二叉搜索树即可。 你可以返回 任意有效的结果 。\n\n--\n\n![](./img/701/1.png)\n\n--\n\n![](./img/701/2.png)\n\n--\n\n```java\nclass Solution {\n    public TreeNode insertIntoBST(TreeNode root, int val) {\n        if (null == root){\n            return new TreeNode(val);\n        }\n        if (val < root.val){\n            root.left = insertIntoBST(root.left, val);\n        } else {\n            root.right = insertIntoBST(root.right, val);\n        }\n        return root;\n    }\n}\n```\n\n---\n\n## 700-二叉搜索树中的搜索\n\n![](./img/700/1.png)\n\n--\n\n```java\nclass Solution {\n    public TreeNode searchBST(TreeNode root, int val) {\n        if (null == root){\n            return null;\n        }\n        if (val == root.val){\n            return root;\n        }\n        if (val > root.val){\n            return searchBST(root.right, val);\n        } else {\n            return searchBST(root.left, val);\n        }\n    }\n}\n```\n\n---\n\n## 98-验证二叉搜索树\n\n![](./img/98/1.png)\n\n--\n\n```java\nclass Solution {\n    public boolean isValidBST(TreeNode root) {\n        return isValidBST(root, null, null);\n    }\n\n    private boolean isValidBST(TreeNode root, TreeNode min, TreeNode max){\n        if (null == root){\n            return true;\n        }\n\n        if (null != min && root.val <= min.val){\n            return false;\n        }\n\n        if (null != max && root.val >= max.val){\n            return false;\n        }\n\n        return isValidBST(root.left, min, root) && isValidBST(root.right, root, max);\n    }\n}\n```\n"}},l=Object(t.a)({},(function(){var n=this.$createElement,o=this._self._c||n;return o("ContentSlotsDistributor",{attrs:{"slot-key":this.$parent.slotKey}},[o("Presentation",{key:"presentation_1a96284a",attrs:{id:"presentation_1a96284a",code:this.$dataBlock.presentation_1a96284a,theme:"auto"}})],1)}),[],!1,null,null,null);"function"==typeof r&&r(l);o.default=l.exports}}]);